import java.util.Locale

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            ZionTheme {
                val view = LocalView.current
                if (!view.isInEditMode) {
                    SideEffect {
                        val window = (view.context as android.app.Activity).window
                        WindowCompat.getInsetsController(window, view).isAppearanceLightStatusBars = false
                        WindowCompat.getInsetsController(window, view).isAppearanceLightNavigationBars = false
                    }
                }
                MainScreen()
            }
        }
    }
}

@Composable
fun MainScreen(viewModel: MusicViewModel = viewModel()) {
    val context = LocalContext.current
    val tracks by viewModel.tracks.collectAsState()
    val isLoading by viewModel.isLoading.collectAsState()
    val currentTrack by viewModel.currentTrack.collectAsState()
    val isPlaying by viewModel.isPlaying.collectAsState()
    val currentPosition by viewModel.currentPosition.collectAsState()
    val duration by viewModel.duration.collectAsState()
    val completedTracks by viewModel.completedTracks.collectAsState()

    val hasFullAccess = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
        Environment.isExternalStorageManager()
    } else {
        true
    }

    val launcher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenDocumentTree()
    ) { uri: Uri? ->
        uri?.let { viewModel.loadDirectory(it) }
    }

    Scaffold(
        modifier = Modifier.fillMaxSize(),
        floatingActionButton = {
            FloatingActionButton(
                onClick = { launcher.launch(null) },
                containerColor = CyanAccent,
                contentColor = Color.Black,
                modifier = Modifier.navigationBarsPadding() 
            ) {
                Icon(Icons.Default.FolderOpen, contentDescription = "Open Folder")
            }
        },
        bottomBar = {
            currentTrack?.let { track ->
                PlayerBar(
                    track = track,
                    isPlaying = isPlaying,
                    currentPosition = currentPosition,
                    duration = duration,
                    onTogglePlay = { viewModel.togglePlayPause() },
                    onNext = { viewModel.playNextTrack() },
                    onPrevious = { viewModel.playPreviousTrack() },
                    onShuffle = { viewModel.shuffle() },
                    onSeek = { viewModel.seekTo(it) },
                    onExit = { viewModel.stopAndExit() },
                    viewModel = viewModel
                )
            }
        }
    ) { innerPadding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .background(MaterialTheme.colorScheme.background)
        ) {
            if (tracks.isEmpty()) {
                EmptyState(
                    hasFullAccess = hasFullAccess,
                    isLoading = isLoading,
                    onGrantAccess = {
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
                            val intent = Intent(Settings.ACTION_MANAGE_APP_ALL_FILES_ACCESS_PERMISSION).apply {
                                data = Uri.parse("package:${context.packageName}")
                            }
                            context.startActivity(intent)
                        }
                    },
                    onRefresh = { viewModel.scanAllMusic() }
                )
            } else {
                TrackList(
                    tracks = tracks, 
                    currentTrack = currentTrack,
                    completedTracks = completedTracks,
                    onTrackClick = { viewModel.playTrack(it) },
                    onTrackLongClick = { 
                        vibrate(context)
                        viewModel.toggleTrackCompleted(it)
                    }
                )

                if (isLoading) {
                    LinearProgressIndicator(
                        modifier = Modifier.fillMaxWidth().align(Alignment.TopCenter),
                        color = CyanAccent,
                        trackColor = Color.Transparent
                    )
                }
            }
        }
    }
}

private fun vibrate(context: Context) {
    val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
        val vibratorManager = context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as VibratorManager
        vibratorManager.defaultVibrator
    } else {
        @Suppress("DEPRECATION")
        context.getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
    }
    vibrator.vibrate(VibrationEffect.createOneShot(50, VibrationEffect.DEFAULT_AMPLITUDE))
}

@Composable
fun PlayerBar(
    track: Track,
    isPlaying: Boolean,
    currentPosition: Long,
    duration: Long,
    onTogglePlay: () -> Unit,
    onNext: () -> Unit,
    onPrevious: () -> Unit,
    onShuffle: () -> Unit,
    onSeek: (Long) -> Unit,
    onExit: () -> Unit,
    viewModel: MusicViewModel
) {
    val barColor = MaterialTheme.colorScheme.surfaceVariant
    val context = LocalContext.current
    val view = LocalView.current

    val speeds = listOf(0.5f, 1.0f, 1.5f, 2.0f)
    var currentSpeedIndex by remember { mutableStateOf(1) }

    var currentVolumePercent by remember { mutableStateOf(0) }
    val audioManager = remember { context.getSystemService(Context.AUDIO_SERVICE) as AudioManager }

    LaunchedEffect(Unit) {
        while (true) {
            val max = audioManager.getStreamMaxVolume(AudioManager.STREAM_MUSIC)
            val current = audioManager.getStreamVolume(AudioManager.STREAM_MUSIC)
            currentVolumePercent = (current.toFloat() / max.toFloat() * 100).toInt()
            delay(500)
        }
    }

    if (!view.isInEditMode) {
        SideEffect {
            val window = (view.context as android.app.Activity).window
            window.navigationBarColor = android.graphics.Color.argb(255, (barColor.red * 255).toInt(), (barColor.green * 255).toInt(), (barColor.blue * 255).toInt())
        }
    }

    Column(
        modifier = Modifier
            .fillMaxWidth()
            .background(
                brush = Brush.verticalGradient(
                    colors = listOf(barColor.copy(alpha = 0.9f), barColor)
                ),
                shape = RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp)
            )
            .navigationBarsPadding() 
    ) {
        Column(
            modifier = Modifier
                .padding(horizontal = 20.dp, vertical = 24.dp)
                .fillMaxWidth(),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(onClick = onShuffle, modifier = Modifier.size(36.dp)) {
                    Icon(Icons.Default.Shuffle, contentDescription = null, tint = Color.White.copy(alpha = 0.4f), modifier = Modifier.size(20.dp))
                }

                Column(modifier = Modifier.weight(1f), horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(text = track.title.uppercase(), style = MaterialTheme.typography.bodyLarge.copy(fontWeight = FontWeight.Bold, letterSpacing = 1.2.sp, color = Color.White), textAlign = TextAlign.Center, maxLines = 1)
                    Text(text = (track.artist ?: "UNKNOWN").uppercase(), style = MaterialTheme.typography.labelMedium.copy(color = CyanAccent, letterSpacing = 1.2.sp), textAlign = TextAlign.Center, maxLines = 1)
                }

                IconButton(onClick = onExit, modifier = Modifier.size(36.dp)) {
                    Icon(Icons.Default.Close, contentDescription = null, tint = Color.White.copy(alpha = 0.4f), modifier = Modifier.size(20.dp))
                }
            }

            Spacer(modifier = Modifier.height(20.dp))

            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Text(text = formatTime(currentPosition), style = MaterialTheme.typography.labelSmall.copy(fontSize = 11.sp, color = Color.White.copy(alpha = 0.5f)), modifier = Modifier.width(40.dp), textAlign = TextAlign.End)
                Slider(value = if (duration > 0) currentPosition.toFloat() else 0f, onValueChange = { onSeek(it.toLong()) }, valueRange = 0f..(if (duration > 0) duration.toFloat() else 1f), modifier = Modifier.weight(1f).height(28.dp), colors = SliderDefaults.colors(thumbColor = Color.White, activeTrackColor = CyanAccent, inactiveTrackColor = Color.White.copy(alpha = 0.1f)))
                Text(text = formatTime(duration), style = MaterialTheme.typography.labelSmall.copy(fontSize = 11.sp, color = Color.White.copy(alpha = 0.5f)), modifier = Modifier.width(40.dp), textAlign = TextAlign.Start)
            }

            Spacer(modifier = Modifier.height(16.dp))

            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(
                    text = "$currentVolumePercent%",
                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold, color = Color.White.copy(alpha = 0.4f)),
                    modifier = Modifier.width(48.dp),
                    textAlign = TextAlign.Center
                )

                Row(verticalAlignment = Alignment.CenterVertically) {
                    val scope = rememberCoroutineScope()

                    // PREVIOUS / REWIND - SECURE LOGIC
                    Box(
                        modifier = Modifier
                            .size(52.dp)
                            .clip(CircleShape)
                            .pointerInput(Unit) {
                                detectTapGestures(
                                    onPress = {
                                        var isLongPressRunning = false
                                        val job = scope.launch {
                                            delay(500)
                                            isLongPressRunning = true
                                            while (isActive) {
                                                val nextPos = (viewModel.currentPosition.value - 10000).coerceAtLeast(0)
                                                onSeek(nextPos)
                                                if (nextPos == 0L) break
                                                delay(200)
                                            }
                                        }
                                        tryAwaitRelease()
                                        job.cancel()
                                        if (!isLongPressRunning) {
                                            onPrevious()
                                        }
                                    }
                                )
                            },
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(Icons.Default.SkipPrevious, contentDescription = null, tint = Color.White, modifier = Modifier.size(32.dp))
                    }

                    Spacer(modifier = Modifier.width(24.dp))

                    Surface(
                        onClick = onTogglePlay,
                        shape = RoundedCornerShape(percent = 50),
                        color = Color.White,
                        modifier = Modifier.size(64.dp)
                    ) {
                        Box(contentAlignment = Alignment.Center) {
                            Icon(imageVector = if (isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow, contentDescription = null, tint = Color.Black, modifier = Modifier.size(36.dp))
                        }
                    }

                    Spacer(modifier = Modifier.width(24.dp))

                    // NEXT / FAST FORWARD - SECURE LOGIC
                    Box(
                        modifier = Modifier
                            .size(52.dp)
                            .clip(CircleShape)
                            .pointerInput(Unit) {
                                detectTapGestures(
                                    onPress = {
                                        var isLongPressRunning = false
                                        val job = scope.launch {
                                            delay(500)
                                            isLongPressRunning = true
                                            while (isActive) {
                                                val nextPos = (viewModel.currentPosition.value + 10000).coerceAtMost(viewModel.duration.value)
                                                onSeek(nextPos)
                                                if (nextPos == viewModel.duration.value) break
                                                delay(200)
                                            }
                                        }
                                        tryAwaitRelease()
                                        job.cancel()
                                        if (!isLongPressRunning) {
                                            onNext()
                                        }
                                    }
                                )
                            },
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(Icons.Default.SkipNext, contentDescription = null, tint = Color.White, modifier = Modifier.size(32.dp))
                    }
                }

                TextButton(
                    onClick = {
                        currentSpeedIndex = (currentSpeedIndex + 1) % speeds.size
                        viewModel.setPlaybackSpeed(speeds[currentSpeedIndex])
                    },
                    modifier = Modifier.width(48.dp),
                    contentPadding = PaddingValues(0.dp)
                ) {
                    Text(text = "${speeds[currentSpeedIndex]}X", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold, color = Color.White.copy(alpha = 0.4f)))
                }
            }
        }
    }
}

private fun formatTime(ms: Long): String {
    val totalSeconds = ms / 1000
    val minutes = totalSeconds / 60
    val seconds = totalSeconds % 60
    return String.format(Locale.getDefault(), "%02d:%02d", minutes, seconds)
}

@Composable
fun TrackList(
    tracks: List<Track>, 
    currentTrack: Track?,
    completedTracks: Set<String>,
    onTrackClick: (Track) -> Unit,
    onTrackLongClick: (Track) -> Unit
) {
    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(bottom = 240.dp, start = 24.dp, end = 24.dp, top = 24.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        item {
            Text(text = "LIBRARY", style = MaterialTheme.typography.labelMedium.copy(letterSpacing = 4.sp, color = CyanAccent), modifier = Modifier.padding(bottom = 16.dp))
        }
        items(tracks, key = { it.uri.toString() + "_" + it.startTimeMs }) { track ->
            TrackItem(
                track = track, 
                isCurrent = track == currentTrack,
                isCompleted = completedTracks.contains(track.uri.toString()),
                onClick = { onTrackClick(track) },
                onLongClick = { onTrackLongClick(track) }
            )
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)
@Composable
fun TrackItem(track: Track, isCurrent: Boolean, isCompleted: Boolean, onClick: () -> Unit, onLongClick: () -> Unit) {
    val context = LocalContext.current
    var artworkBitmap by remember(track.uri) { mutableStateOf<android.graphics.Bitmap?>(null) }

    LaunchedEffect(track.uri) {
        withContext(Dispatchers.IO) {
            val retriever = MediaMetadataRetriever()
            try {
                retriever.setDataSource(context, track.uri)
                val art = retriever.embeddedPicture
                if (art != null) {
                    val bitmap = BitmapFactory.decodeByteArray(art, 0, art.size)
                    if (bitmap != null) {
                        val scaledBitmap = android.graphics.Bitmap.createScaledBitmap(bitmap, 150, 150, true)
                        artworkBitmap = scaledBitmap
                        if (bitmap != scaledBitmap) bitmap.recycle()
                    }
                }
            } catch (e: Exception) {
                artworkBitmap = null
            } finally {
                try { retriever.release() } catch (e: Exception) {}
            }
        }
    }

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .combinedClickable(
                onClick = onClick,
                onLongClick = onLongClick
            )
            .padding(vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(
            modifier = Modifier
                .size(48.dp)
                .clip(RoundedCornerShape(4.dp))
                .background(brush = if (isCurrent) Brush.linearGradient(listOf(Color.White, Color.White)) else Brush.linearGradient(listOf(CyanAccent, VioletAccent)), alpha = if (isCurrent) 1.0f else 0.1f),
            contentAlignment = Alignment.Center
        ) {
            if (artworkBitmap != null) {
                Image(
                    bitmap = artworkBitmap!!.asImageBitmap(), 
                    contentDescription = null, 
                    modifier = Modifier.fillMaxSize(), 
                    contentScale = ContentScale.Crop
                )
            } else {
                Icon(
                    Icons.Default.MusicNote, 
                    contentDescription = null, 
                    tint = if (isCurrent) Color.Black else if (track.isCueTrack) VioletAccent else CyanAccent, 
                    modifier = Modifier.size(24.dp)
                )
            }
        }

        Spacer(modifier = Modifier.width(16.dp))

        Column {
            Text(
                text = track.title.uppercase(), 
                style = MaterialTheme.typography.bodyLarge.copy(
                    fontWeight = FontWeight.Medium, 
                    letterSpacing = 1.sp, 
                    color = if (isCurrent) CyanAccent 
                            else if (isCompleted) Color.White.copy(alpha = 0.35f) 
                            else MaterialTheme.colorScheme.onBackground
                ), 
                maxLines = 1
            )
            Text(
                text = (track.artist ?: "UNKNOWN").uppercase(), 
                style = MaterialTheme.typography.bodySmall.copy(
                    letterSpacing = 1.sp, 
                    color = if (isCurrent) CyanAccent.copy(alpha = 0.7f) 
                            else if (isCompleted) Color.White.copy(alpha = 0.25f) 
                            else MaterialTheme.colorScheme.onBackground.copy(alpha = 0.5f)
                ), 
                maxLines = 1
            )
        }
    }
}

@Composable
fun EmptyState(hasFullAccess: Boolean, isLoading: Boolean, onGrantAccess: () -> Unit, onRefresh: () -> Unit) {
    Column(
        modifier = Modifier.fillMaxSize(),
        verticalArrangement = Arrangement.Center,
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Box(
            modifier = Modifier
                .size(120.dp)
                .background(brush = Brush.linearGradient(listOf(CyanAccent, VioletAccent)), shape = RoundedCornerShape(28.dp), alpha = 0.15f),
            contentAlignment = Alignment.Center
        ) {
            Text(text = "Z", style = MaterialTheme.typography.displayLarge.copy(fontWeight = FontWeight.Black, color = CyanAccent, fontSize = 80.sp))
        }
        Spacer(modifier = Modifier.height(24.dp))
        Text(text = "ZION", style = MaterialTheme.typography.displayLarge.copy(fontWeight = FontWeight.ExtraLight, letterSpacing = 12.sp, color = Color.White))
        Text(text = "PREMIUM OFFLINE AUDIO", style = MaterialTheme.typography.labelSmall.copy(letterSpacing = 4.sp, color = CyanAccent.copy(alpha = 0.6f)))
        Spacer(modifier = Modifier.height(48.dp))
        if (isLoading) {
            CircularProgressIndicator(color = CyanAccent)
        } else {
            if (!hasFullAccess) {
                Button(onClick = onGrantAccess, colors = ButtonDefaults.buttonColors(containerColor = CyanAccent), shape = RoundedCornerShape(8.dp)) {
                    Icon(Icons.Default.Security, contentDescription = null, tint = Color.Black)
                    Spacer(modifier = Modifier.width(8.dp))
                    Text("GRANT FULL STORAGE ACCESS", color = Color.Black, fontWeight = FontWeight.Bold)
                }
            } else {
                Button(onClick = onRefresh, colors = ButtonDefaults.buttonColors(containerColor = CyanAccent.copy(alpha = 0.2f)), shape = RoundedCornerShape(8.dp)) {
                    Text("SCAN MUSIC LIBRARY", color = CyanAccent)
                }
            }
            Spacer(modifier = Modifier.height(24.dp))
            Text(text = "OR SELECT A FOLDER MANUALLY", style = MaterialTheme.typography.labelLarge.copy(letterSpacing = 2.sp, color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.4f)))
        }
    }
}

package com.example.zion

import android.app.Application
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.media.MediaMetadataRetriever
import android.net.Uri
import android.os.Build
import android.os.Environment
import androidx.annotation.OptIn
import androidx.documentfile.provider.DocumentFile
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import androidx.media3.common.MediaItem
import androidx.media3.common.MediaMetadata
import androidx.media3.common.PlaybackParameters
import androidx.media3.common.Player
import androidx.media3.common.util.UnstableApi
import androidx.media3.session.MediaController
import androidx.media3.session.SessionToken
import com.example.zion.model.Track
import com.example.zion.util.CueParser
import com.google.common.util.concurrent.ListenableFuture
import com.google.common.util.concurrent.MoreExecutors
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.ByteArrayOutputStream
import java.io.File
import kotlin.random.Random

class MusicViewModel(application: Application) : AndroidViewModel(application) {

    private val prefs = application.getSharedPreferences("zion_prefs", Context.MODE_PRIVATE)

    private val _tracks = MutableStateFlow<List<Track>>(emptyList())
    val tracks: StateFlow<List<Track>> = _tracks

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading

    private val _currentTrack = MutableStateFlow<Track?>(null)
    val currentTrack: StateFlow<Track?> = _currentTrack

    private val _isPlaying = MutableStateFlow(false)
    val isPlaying: StateFlow<Boolean> = _isPlaying

    private val _currentPosition = MutableStateFlow(0L)
    val currentPosition: StateFlow<Long> = _currentPosition

    private val _duration = MutableStateFlow(0L)
    val duration: StateFlow<Long> = _duration

    private val _completedTracks = MutableStateFlow<Set<String>>(emptySet())
    val completedTracks: StateFlow<Set<String>> = _completedTracks

    private var controllerFuture: ListenableFuture<MediaController>? = null
    private val controller: MediaController?
        get() = if (controllerFuture?.isDone == true) controllerFuture?.get() else null

    private var isRestoring = false

    private val supportedExtensions = setOf(
        "mp3", "m4a", "aac", "ogg", "opus", "flac", "wav", "aiff", "wma", "alac", 
        "pcm", "amr", "mid", "midi", "mka", "wv", "ape", "au", "dsf", "dff", 
        "mpc", "ra", "rm"
    )

    init {
        // 1. Load persistence data immediately
        val savedCompleted = prefs.getStringSet("completed_tracks_paths", emptySet()) ?: emptySet()
        _completedTracks.value = savedCompleted

        // 2. Setup MediaController
        val sessionToken = SessionToken(application, ComponentName(application, PlaybackService::class.java))
        controllerFuture = MediaController.Builder(application, sessionToken).buildAsync()
        controllerFuture?.addListener({
            setupController()
            restoreLastState()
        }, MoreExecutors.directExecutor())

        // 3. FAST LOAD last used location
        viewModelScope.launch {
            val lastPath = prefs.getString("last_directory_path", null)
            val lastUri = prefs.getString("last_directory_uri", null)

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R && Environment.isExternalStorageManager() && lastPath != null) {
                scanLocalPath(File(lastPath))
            } else if (lastUri != null) {
                loadDirectory(Uri.parse(lastUri), isAutoLoad = true)
            }
        }

        // 4. Background Progress Tracking
        viewModelScope.launch {
            while (isActive) {
                controller?.let {
                    if (it.isPlaying) {
                        _currentPosition.value = it.currentPosition
                        savePlaybackState(it.currentPosition)
                        checkTrackCompletion(it.currentPosition, it.duration)
                    }
                }
                delay(1000)
            }
        }
    }

    private fun setupController() {
        val controller = this.controller ?: return
        controller.addListener(object : Player.Listener {
            override fun onIsPlayingChanged(isPlaying: Boolean) {
                _isPlaying.value = isPlaying
                if (!isPlaying) {
                    savePlaybackState(controller.currentPosition)
                }
            }
            override fun onMediaItemTransition(mediaItem: MediaItem?, reason: Int) {
                updateCurrentTrackFromMediaItem(mediaItem)
            }
            override fun onPlaybackStateChanged(playbackState: Int) {
                if (playbackState == Player.STATE_READY) {
                    _duration.value = controller.duration
                    if (isRestoring) {
                        val lastPosition = prefs.getLong("last_track_position", 0L)
                        controller.seekTo(lastPosition)
                        _currentPosition.value = lastPosition
                        isRestoring = false
                    }
                }
                if (playbackState == Player.STATE_ENDED) {
                    _currentTrack.value?.let { markTrackAsCompleted(it) }
                    playNextTrack()
                }
            }
        })
    }

    private fun checkTrackCompletion(current: Long, duration: Long) {
        if (duration > 0) {
            val progress = current.toFloat() / duration.toFloat()
            if (progress >= 0.9f) {
                _currentTrack.value?.let { markTrackAsCompleted(it) }
            }
        }
    }

    private fun markTrackAsCompleted(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.add(path)) {
            _completedTracks.value = currentSet
            prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
        }
    }

    fun toggleTrackCompleted(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.contains(path)) {
            currentSet.remove(path)
        } else {
            currentSet.add(path)
        }
        _completedTracks.value = currentSet
        prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
    }

    fun markTrackAsUnplayed(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.remove(path)) {
            _completedTracks.value = currentSet
            prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
        }
    }

    private fun restoreLastState() {
        val lastTrackUri = prefs.getString("last_track_uri", null) ?: return

        viewModelScope.launch {
            // Wait for tracks to be loaded (max 5 seconds)
            var attempts = 0
            while (_tracks.value.isEmpty() && attempts < 25) {
                delay(250)
                attempts++
            }

            val track = _tracks.value.find { it.uri.toString() == lastTrackUri }
            if (track != null && _currentTrack.value == null) {
                isRestoring = true
                prepareTrack(track)
            }
        }
    }

    private fun savePlaybackState(position: Long) {
        val current = _currentTrack.value ?: return
        if (position > 0) {
            prefs.edit()
                .putString("last_track_uri", current.uri.toString())
                .putLong("last_track_position", position)
                .apply()
        }
    }

    private fun updateCurrentTrackFromMediaItem(mediaItem: MediaItem?) {
        if (mediaItem == null) return
        val uri = mediaItem.localConfiguration?.uri?.toString() ?: return
        val normalizedUri = uri.substringBefore("_") 
        _currentTrack.value = _tracks.value.find { it.uri.toString().contains(normalizedUri) }
    }

    fun scanAllMusic() {
        val musicFolder = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_MUSIC)
        // Persist the root path so it auto-loads next time
        prefs.edit().putString("last_directory_path", musicFolder.absolutePath).apply()

        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                recursiveScan(musicFolder)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    fun scanLocalPath(file: File) {
        prefs.edit().putString("last_directory_path", file.absolutePath).apply()
        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                recursiveScan(file)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    private fun recursiveScan(file: File): List<Track> {
        val trackList = mutableListOf<Track>()
        val files = file.listFiles() ?: return emptyList()

        val cueFiles = mutableListOf<File>()
        val audioFiles = mutableMapOf<String, File>()

        files.forEach { f ->
            if (f.isDirectory) {
                trackList.addAll(recursiveScan(f))
            } else {
                val ext = f.extension.lowercase()
                if (supportedExtensions.contains(ext)) {
                    audioFiles[f.name] = f
                } else if (ext == "cue") {
                    cueFiles.add(f)
                }
            }
        }

        val handledFiles = mutableSetOf<String>()
        cueFiles.forEach { cueFile ->
            try {
                val content = cueFile.readText()
                val cueSheet = CueParser.parse(content)
                cueSheet?.let { sheet ->
                    if (audioFiles.containsKey(sheet.file)) {
                        val audioFile = audioFiles[sheet.file]!!
                        handledFiles.add(sheet.file)
                        sheet.tracks.forEach { cueTrack ->
                            trackList.add(
                                Track(
                                    title = cueTrack.title,
                                    artist = cueTrack.performer,
                                    uri = Uri.fromFile(audioFile),
                                    isCueTrack = true,
                                    startTimeMs = cueTrack.startTimeMs,
                                    parentFileName = sheet.file,
                                    artwork = null 
                                )
                            )
                        }
                    }
                }
            } catch (e: Exception) { e.printStackTrace() }
        }

        audioFiles.forEach { (name, f) ->
            if (!handledFiles.contains(name)) {
                trackList.add(
                    Track(
                        title = f.nameWithoutExtension,
                        artist = "Unknown Artist",
                        uri = Uri.fromFile(f),
                        artwork = null 
                    )
                )
            }
        }
        return trackList
    }

    fun loadDirectory(directoryUri: Uri, isAutoLoad: Boolean = false) {
        val context = getApplication<Application>().applicationContext

        val lastUriString = prefs.getString("last_directory_uri", null)
        if (!isAutoLoad && lastUriString != null && lastUriString != directoryUri.toString()) {
            _completedTracks.value = emptySet()
            prefs.edit().remove("completed_tracks_paths").apply()
        }

        try {
            if (directoryUri.scheme == "content") {
                context.contentResolver.takePersistableUriPermission(
                    directoryUri,
                    Intent.FLAG_GRANT_READ_URI_PERMISSION
                )
            }
            prefs.edit().putString("last_directory_uri", directoryUri.toString()).apply()
        } catch (e: Exception) {
            e.printStackTrace()
        }

        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                scanFolder(directoryUri)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    private fun Track.toMediaItem(context: Context, includeArtwork: Boolean): MediaItem {
        val builder = MediaMetadata.Builder()
            .setTitle(title)
            .setArtist(artist)

        if (includeArtwork) {
            val art = getArtworkDataFromUri(context, uri)
            if (art != null) {
                builder.setArtworkData(art, MediaMetadata.PICTURE_TYPE_FRONT_COVER)
            }
        }

        return MediaItem.Builder()
            .setUri(uri)
            .setMediaId(uri.toString() + "_" + startTimeMs)
            .setMediaMetadata(builder.build())
            .build()
    }

    @OptIn(UnstableApi::class)
    fun playTrack(track: Track) {
        val controller = this.controller ?: return
        val context = getApplication<Application>().applicationContext
        isRestoring = false
        _currentTrack.value = track

        viewModelScope.launch {
            val mediaItems = _tracks.value.map { it.toMediaItem(context, it == track) }
            val index = _tracks.value.indexOf(track)
            if (index != -1) {
                controller.setMediaItems(mediaItems, index, if (track.isCueTrack) track.startTimeMs else 0L)
                controller.prepare()
                controller.play()
            }
        }
    }

    @OptIn(UnstableApi::class)
    private fun prepareTrack(track: Track) {
        val controller = this.controller ?: return
        val context = getApplication<Application>().applicationContext
        _currentTrack.value = track

        viewModelScope.launch {
            val mediaItems = _tracks.value.map { it.toMediaItem(context, it == track) }
            val index = _tracks.value.indexOf(track)
            if (index != -1) {
                controller.setMediaItems(mediaItems, index, 0L)
                controller.prepare()
            }
        }
    }

    fun playNextTrack() {
        controller?.seekToNextMediaItem()
    }

    fun playPreviousTrack() {
        controller?.seekToPreviousMediaItem()
    }

    fun shuffle() {
        val currentList = _tracks.value
        if (currentList.isNotEmpty()) {
            val randomIndex = Random.nextInt(currentList.size)
            playTrack(currentList[randomIndex])
        }
    }

    fun seekTo(position: Long) {
        controller?.seekTo(position)
        _currentPosition.value = position
        savePlaybackState(position)
    }

    fun togglePlayPause() {
        controller?.let {
            if (it.isPlaying) it.pause() else it.play()
        }
    }

    fun setPlaybackSpeed(speed: Float) {
        controller?.playbackParameters = PlaybackParameters(speed)
    }

    fun stopAndExit() {
        controller?.stop()
        val intent = Intent(getApplication<Application>(), PlaybackService::class.java)
        getApplication<Application>().stopService(intent)
        System.exit(0)
    }

    override fun onCleared() {
        super.onCleared()
        controllerFuture?.let {
            MediaController.releaseFuture(it)
        }
    }

    private fun scanFolder(directoryUri: Uri): List<Track> {
        val context = getApplication<Application>().applicationContext
        val rootDoc = DocumentFile.fromTreeUri(context, directoryUri) ?: return emptyList()
        val trackList = mutableListOf<Track>()
        val cueFiles = mutableListOf<DocumentFile>()
        val audioFiles = mutableMapOf<String, DocumentFile>()

        rootDoc.listFiles().forEach { file ->
            val name = file.name ?: ""
            val ext = name.substringAfterLast(".", "").lowercase()
            if (supportedExtensions.contains(ext)) {
                audioFiles[name] = file
            } else if (ext == "cue") {
                cueFiles.add(file)
            }
        }

        cueFiles.forEach { cueDoc ->
            try {
                val content = context.contentResolver.openInputStream(cueDoc.uri)?.use { it.bufferedReader().readText() } ?: ""
                val cueSheet = CueParser.parse(content)
                cueSheet?.let { sheet ->
                    if (audioFiles.containsKey(sheet.file)) {
                        val audioDoc = audioFiles[sheet.file]!!
                        sheet.tracks.forEach { cueTrack ->
                            trackList.add(Track(cueTrack.title, cueTrack.performer, 0, audioDoc.uri, true, cueTrack.startTimeMs, sheet.file, null))
                        }
                    }
                }
            } catch (e: Exception) { e.printStackTrace() }
        }

        audioFiles.forEach { (name, doc) ->
            if (trackList.none { it.parentFileName == name }) {
                trackList.add(Track(name.substringBeforeLast("."), "Unknown Artist", 0, doc.uri, false, 0, null, null))
            }
        }
        return trackList
    }

    private fun getArtworkDataFromUri(context: Context, uri: Uri): ByteArray? {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(context, uri)
            val art = retriever.embeddedPicture
            if (art != null) {
                val bitmap = BitmapFactory.decodeByteArray(art, 0, art.size)
                val scaledBitmap = Bitmap.createScaledBitmap(bitmap, 200, 200, true)
                val out = ByteArrayOutputStream()
                scaledBitmap.compress(Bitmap.CompressFormat.JPEG, 70, out)
                out.toByteArray()
            } else null
        } catch (e: Exception) { null } finally { try { retriever.release() } catch (e: Exception) {} }
    }
}

package com.example.zion

import android.app.Application
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.media.MediaMetadataRetriever
import android.net.Uri
import android.os.Build
import android.os.Environment
import androidx.annotation.OptIn
import androidx.documentfile.provider.DocumentFile
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import androidx.media3.common.MediaItem
import androidx.media3.common.MediaMetadata
import androidx.media3.common.PlaybackParameters
import androidx.media3.common.Player
import androidx.media3.common.util.UnstableApi
import androidx.media3.session.MediaController
import androidx.media3.session.SessionToken
import com.example.zion.model.Track
import com.example.zion.util.CueParser
import com.google.common.util.concurrent.ListenableFuture
import com.google.common.util.concurrent.MoreExecutors
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.ByteArrayOutputStream
import java.io.File
import kotlin.random.Random

class MusicViewModel(application: Application) : AndroidViewModel(application) {

    private val prefs = application.getSharedPreferences("zion_prefs", Context.MODE_PRIVATE)

    private val _tracks = MutableStateFlow<List<Track>>(emptyList())
    val tracks: StateFlow<List<Track>> = _tracks

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading

    private val _currentTrack = MutableStateFlow<Track?>(null)
    val currentTrack: StateFlow<Track?> = _currentTrack

    private val _isPlaying = MutableStateFlow(false)
    val isPlaying: StateFlow<Boolean> = _isPlaying

    private val _currentPosition = MutableStateFlow(0L)
    val currentPosition: StateFlow<Long> = _currentPosition

    private val _duration = MutableStateFlow(0L)
    val duration: StateFlow<Long> = _duration

    private val _completedTracks = MutableStateFlow<Set<String>>(emptySet())
    val completedTracks: StateFlow<Set<String>> = _completedTracks

    private var controllerFuture: ListenableFuture<MediaController>? = null
    private val controller: MediaController?
        get() = if (controllerFuture?.isDone == true) controllerFuture?.get() else null

    private var isRestoring = false

    private val supportedExtensions = setOf(
        "mp3", "m4a", "aac", "ogg", "opus", "flac", "wav", "aiff", "wma", "alac", 
        "pcm", "amr", "mid", "midi", "mka", "wv", "ape", "au", "dsf", "dff", 
        "mpc", "ra", "rm"
    )

    init {
        // 1. Load persistence data immediately
        val savedCompleted = prefs.getStringSet("completed_tracks_paths", emptySet()) ?: emptySet()
        _completedTracks.value = savedCompleted

        // 2. Setup MediaController
        val sessionToken = SessionToken(application, ComponentName(application, PlaybackService::class.java))
        controllerFuture = MediaController.Builder(application, sessionToken).buildAsync()
        controllerFuture?.addListener({
            setupController()
            restoreLastState()
        }, MoreExecutors.directExecutor())

        // 3. FAST LOAD last used location
        viewModelScope.launch {
            val lastPath = prefs.getString("last_directory_path", null)
            val lastUri = prefs.getString("last_directory_uri", null)

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R && Environment.isExternalStorageManager() && lastPath != null) {
                scanLocalPath(File(lastPath))
            } else if (lastUri != null) {
                loadDirectory(Uri.parse(lastUri), isAutoLoad = true)
            }
        }

        // 4. Background Progress Tracking
        viewModelScope.launch {
            while (isActive) {
                controller?.let {
                    if (it.isPlaying) {
                        _currentPosition.value = it.currentPosition
                        savePlaybackState(it.currentPosition)
                        checkTrackCompletion(it.currentPosition, it.duration)
                    }
                }
                delay(1000)
            }
        }
    }

    private fun setupController() {
        val controller = this.controller ?: return
        controller.addListener(object : Player.Listener {
            override fun onIsPlayingChanged(isPlaying: Boolean) {
                _isPlaying.value = isPlaying
                if (!isPlaying) {
                    savePlaybackState(controller.currentPosition)
                }
            }
            override fun onMediaItemTransition(mediaItem: MediaItem?, reason: Int) {
                updateCurrentTrackFromMediaItem(mediaItem)
            }
            override fun onPlaybackStateChanged(playbackState: Int) {
                if (playbackState == Player.STATE_READY) {
                    _duration.value = controller.duration
                    if (isRestoring) {
                        val lastPosition = prefs.getLong("last_track_position", 0L)
                        controller.seekTo(lastPosition)
                        _currentPosition.value = lastPosition
                        isRestoring = false
                    }
                }
                if (playbackState == Player.STATE_ENDED) {
                    _currentTrack.value?.let { markTrackAsCompleted(it) }
                    playNextTrack()
                }
            }
        })
    }

    private fun checkTrackCompletion(current: Long, duration: Long) {
        if (duration > 0) {
            val progress = current.toFloat() / duration.toFloat()
            if (progress >= 0.9f) {
                _currentTrack.value?.let { markTrackAsCompleted(it) }
            }
        }
    }

    private fun markTrackAsCompleted(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.add(path)) {
            _completedTracks.value = currentSet
            prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
        }
    }

    fun toggleTrackCompleted(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.contains(path)) {
            currentSet.remove(path)
        } else {
            currentSet.add(path)
        }
        _completedTracks.value = currentSet
        prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
    }

    fun markTrackAsUnplayed(track: Track) {
        val path = track.uri.toString()
        val currentSet = _completedTracks.value.toMutableSet()
        if (currentSet.remove(path)) {
            _completedTracks.value = currentSet
            prefs.edit().putStringSet("completed_tracks_paths", currentSet).apply()
        }
    }

    private fun restoreLastState() {
        val lastTrackUri = prefs.getString("last_track_uri", null) ?: return

        viewModelScope.launch {
            // Wait for tracks to be loaded (max 5 seconds)
            var attempts = 0
            while (_tracks.value.isEmpty() && attempts < 25) {
                delay(250)
                attempts++
            }

            val track = _tracks.value.find { it.uri.toString() == lastTrackUri }
            if (track != null && _currentTrack.value == null) {
                isRestoring = true
                prepareTrack(track)
            }
        }
    }

    private fun savePlaybackState(position: Long) {
        val current = _currentTrack.value ?: return
        if (position > 0) {
            prefs.edit()
                .putString("last_track_uri", current.uri.toString())
                .putLong("last_track_position", position)
                .apply()
        }
    }

    private fun updateCurrentTrackFromMediaItem(mediaItem: MediaItem?) {
        if (mediaItem == null) return
        val uri = mediaItem.localConfiguration?.uri?.toString() ?: return
        val normalizedUri = uri.substringBefore("_") 
        _currentTrack.value = _tracks.value.find { it.uri.toString().contains(normalizedUri) }
    }

    fun scanAllMusic() {
        val musicFolder = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_MUSIC)
        // Persist the root path so it auto-loads next time
        prefs.edit().putString("last_directory_path", musicFolder.absolutePath).apply()

        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                recursiveScan(musicFolder)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    fun scanLocalPath(file: File) {
        prefs.edit().putString("last_directory_path", file.absolutePath).apply()
        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                recursiveScan(file)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    private fun recursiveScan(file: File, depth: Int = 0): List<Track> {
        // Prevent infinite recursion on deeply nested directories
        if (depth > 20) return emptyList()

        val trackList = mutableListOf<Track>()
        val files = file.listFiles() ?: return emptyList()

        val cueFiles = mutableListOf<File>()
        val audioFiles = mutableMapOf<String, File>()

        files.forEach { f ->
            if (f.isDirectory) {
                trackList.addAll(recursiveScan(f, depth + 1))
            } else {
                val ext = f.extension.lowercase()
                if (supportedExtensions.contains(ext)) {
                    audioFiles[f.name] = f
                } else if (ext == "cue") {
                    cueFiles.add(f)
                }
            }
        }

        val handledFiles = mutableSetOf<String>()
        cueFiles.forEach { cueFile ->
            try {
                val content = cueFile.readText()
                val cueSheet = CueParser.parse(content)
                cueSheet?.let { sheet ->
                    if (audioFiles.containsKey(sheet.file)) {
                        val audioFile = audioFiles[sheet.file]!!
                        handledFiles.add(sheet.file)
                        sheet.tracks.forEach { cueTrack ->
                            trackList.add(
                                Track(
                                    title = cueTrack.title,
                                    artist = cueTrack.performer,
                                    uri = Uri.fromFile(audioFile),
                                    isCueTrack = true,
                                    startTimeMs = cueTrack.startTimeMs,
                                    parentFileName = sheet.file,
                                    artwork = null 
                                )
                            )
                        }
                    }
                }
            } catch (e: Exception) { e.printStackTrace() }
        }

        audioFiles.forEach { (name, f) ->
            if (!handledFiles.contains(name)) {
                trackList.add(
                    Track(
                        title = f.nameWithoutExtension,
                        artist = "Unknown Artist",
                        uri = Uri.fromFile(f),
                        artwork = null 
                    )
                )
            }
        }
        return trackList
    }

    fun loadDirectory(directoryUri: Uri, isAutoLoad: Boolean = false) {
        val context = getApplication<Application>().applicationContext

        val lastUriString = prefs.getString("last_directory_uri", null)
        if (!isAutoLoad && lastUriString != null && lastUriString != directoryUri.toString()) {
            _completedTracks.value = emptySet()
            prefs.edit().remove("completed_tracks_paths").apply()
        }

        try {
            if (directoryUri.scheme == "content") {
                context.contentResolver.takePersistableUriPermission(
                    directoryUri,
                    Intent.FLAG_GRANT_READ_URI_PERMISSION
                )
            }
            prefs.edit().putString("last_directory_uri", directoryUri.toString()).apply()
        } catch (e: Exception) {
            e.printStackTrace()
        }

        viewModelScope.launch {
            _isLoading.value = true
            val scannedTracks = withContext(Dispatchers.IO) {
                scanFolder(directoryUri)
            }
            _tracks.value = scannedTracks
            _isLoading.value = false
        }
    }

    private fun Track.toMediaItem(context: Context, includeArtwork: Boolean): MediaItem {
        val builder = MediaMetadata.Builder()
            .setTitle(title)
            .setArtist(artist)

        if (includeArtwork) {
            val art = getArtworkDataFromUri(context, uri)
            if (art != null) {
                builder.setArtworkData(art, MediaMetadata.PICTURE_TYPE_FRONT_COVER)
            }
        }

        return MediaItem.Builder()
            .setUri(uri)
            .setMediaId(uri.toString() + "_" + startTimeMs)
            .setMediaMetadata(builder.build())
            .build()
    }

    @OptIn(UnstableApi::class)
    fun playTrack(track: Track) {
        val controller = this.controller ?: return
        val context = getApplication<Application>().applicationContext
        isRestoring = false
        _currentTrack.value = track

        viewModelScope.launch {
            val mediaItems = _tracks.value.map { it.toMediaItem(context, it == track) }
            val index = _tracks.value.indexOf(track)
            if (index != -1) {
                controller.setMediaItems(mediaItems, index, if (track.isCueTrack) track.startTimeMs else 0L)
                controller.prepare()
                controller.play()
            }
        }
    }

    @OptIn(UnstableApi::class)
    private fun prepareTrack(track: Track) {
        val controller = this.controller ?: return
        val context = getApplication<Application>().applicationContext
        _currentTrack.value = track

        viewModelScope.launch {
            val mediaItems = _tracks.value.map { it.toMediaItem(context, it == track) }
            val index = _tracks.value.indexOf(track)
            if (index != -1) {
                controller.setMediaItems(mediaItems, index, 0L)
                controller.prepare()
            }
        }
    }

    fun playNextTrack() {
        controller?.seekToNextMediaItem()
    }

    fun playPreviousTrack() {
        controller?.seekToPreviousMediaItem()
    }

    fun shuffle() {
        val currentList = _tracks.value
        if (currentList.isNotEmpty()) {
            val randomIndex = Random.nextInt(currentList.size)
            playTrack(currentList[randomIndex])
        }
    }

    fun seekTo(position: Long) {
        controller?.seekTo(position)
        _currentPosition.value = position
        savePlaybackState(position)
    }

    fun togglePlayPause() {
        controller?.let {
            if (it.isPlaying) it.pause() else it.play()
        }
    }

    fun setPlaybackSpeed(speed: Float) {
        controller?.playbackParameters = PlaybackParameters(speed)
    }

    fun stopAndExit() {
        controller?.stop()
        val intent = Intent(getApplication<Application>(), PlaybackService::class.java)
        getApplication<Application>().stopService(intent)
        // Request activity termination instead of forcefully exiting
        try {
            val context = getApplication<Application>() as? android.app.Activity
            context?.finishAffinity()
        } catch (e: Exception) {
            // Fallback for non-activity context
            Runtime.getRuntime().exit(0)
        }
    }

    override fun onCleared() {
        super.onCleared()
        controllerFuture?.let {
            MediaController.releaseFuture(it)
        }
    }

    private fun scanFolder(directoryUri: Uri): List<Track> {
        val context = getApplication<Application>().applicationContext
        val rootDoc = DocumentFile.fromTreeUri(context, directoryUri) ?: return emptyList()
        val trackList = mutableListOf<Track>()
        val cueFiles = mutableListOf<DocumentFile>()
        val audioFiles = mutableMapOf<String, DocumentFile>()

        rootDoc.listFiles().forEach { file ->
            val name = file.name ?: ""
            val ext = name.substringAfterLast(".", "").lowercase()
            if (supportedExtensions.contains(ext)) {
                audioFiles[name] = file
            } else if (ext == "cue") {
                cueFiles.add(file)
            }
        }

        cueFiles.forEach { cueDoc ->
            try {
                val content = context.contentResolver.openInputStream(cueDoc.uri)?.use { it.bufferedReader().readText() } ?: ""
                val cueSheet = CueParser.parse(content)
                cueSheet?.let { sheet ->
                    if (audioFiles.containsKey(sheet.file)) {
                        val audioDoc = audioFiles[sheet.file]!!
                        sheet.tracks.forEach { cueTrack ->
                            trackList.add(Track(cueTrack.title, cueTrack.performer, 0, audioDoc.uri, true, cueTrack.startTimeMs, sheet.file, null))
                        }
                    }
                }
            } catch (e: Exception) { e.printStackTrace() }
        }

        audioFiles.forEach { (name, doc) ->
            if (trackList.none { it.parentFileName == name }) {
                trackList.add(Track(name.substringBeforeLast("."), "Unknown Artist", 0, doc.uri, false, 0, null, null))
            }
        }
        return trackList
    }

    private fun getArtworkDataFromUri(context: Context, uri: Uri): ByteArray? {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(context, uri)
            val art = retriever.embeddedPicture
            if (art != null) {
                val bitmap = BitmapFactory.decodeByteArray(art, 0, art.size)
                val scaledBitmap = Bitmap.createScaledBitmap(bitmap, 200, 200, true)
                val out = ByteArrayOutputStream()
                scaledBitmap.compress(Bitmap.CompressFormat.JPEG, 70, out)
                out.toByteArray()
            } else null
        } catch (e: Exception) { null } finally { try { retriever.release() } catch (e: Exception) {} }
    }
}

package com.example.zion
import android.app.PendingIntent import android.content.Intent import android.graphics.BitmapFactory import android.os.Bundle import androidx.annotation.OptIn import androidx.media3.common.AudioAttributes import androidx.media3.common.C import androidx.media3.common.MediaItem import androidx.media3.common.MediaMetadata import androidx.media3.common.Player import androidx.media3.common.util.UnstableApi import androidx.media3.exoplayer.ExoPlayer import androidx.media3.session.CommandButton import androidx.media3.session.DefaultMediaNotificationProvider import androidx.media3.session.LibraryResult import androidx.media3.session.MediaLibraryService import androidx.media3.session.MediaNotification import androidx.media3.session.MediaSession import androidx.media3.session.SessionCommand import androidx.media3.session.SessionResult import com.google.common.collect.ImmutableList import com.google.common.util.concurrent.Futures import com.google.common.util.concurrent.ListenableFuture
class PlaybackService : MediaLibraryService() { private var mediaLibrarySession: MediaLibrarySession? = null
companion object { const val CUSTOM_COMMAND_STOP = "STOP_APP" }
@OptIn(UnstableApi::class) override fun onCreate() { super.onCreate()
val audioAttributes = AudioAttributes.Builder() .setContentType(C.AUDIO_CONTENT_TYPE_MUSIC) .setUsage(C.USAGE_MEDIA) .build()
val player = ExoPlayer.Builder(this) .setAudioAttributes(audioAttributes, true) .setHandleAudioBecomingNoisy(true) .build()
val intent = Intent(this, MainActivity::class.java) val pendingIntent = PendingIntent.getActivity( this, 0, intent, PendingIntent.FLAG_IMMUTABLE )
// Previous Button val prevButton = CommandButton.Builder() .setPlayerCommand(Player.COMMAND_SEEK_TO_PREVIOUS) .setIconResId(android.R.drawable.ic_media_previous) .setDisplayName("Previous") .build()
// Next Button val nextButton = CommandButton.Builder() .setPlayerCommand(Player.COMMAND_SEEK_TO_NEXT) .setIconResId(android.R.drawable.ic_media_next) .setDisplayName("Next") .build()
// Stop Button val stopButton = CommandButton.Builder() .setSessionCommand(SessionCommand(CUSTOM_COMMAND_STOP, Bundle.EMPTY)) .setIconResId(android.R.drawable.ic_menu_close_clear_cancel) .setDisplayName("Close") .build()
val callback = object : MediaLibrarySession.Callback { override fun onGetLibraryRoot( session: MediaLibrarySession, browser: MediaSession.ControllerInfo, params: LibraryParams? ): ListenableFuture<LibraryResult<MediaItem>> { val rootMetadata = MediaMetadata.Builder() .setIsBrowsable(true) .setIsPlayable(false) .setMediaType(MediaMetadata.MEDIA_TYPE_FOLDER_MIXED) .setTitle("ZION_ROOT") .build()
val rootItem = MediaItem.Builder() .setMediaId("root") .setMediaMetadata(rootMetadata) .build()
return Futures.immediateFuture(LibraryResult.ofItem(rootItem, params)) }
override fun onConnect( session: MediaSession, controller: MediaSession.ControllerInfo ): MediaSession.ConnectionResult { val sessionCommands = MediaSession.ConnectionResult.DEFAULT_SESSION_COMMANDS.buildUpon() .add(SessionCommand(CUSTOM_COMMAND_STOP, Bundle.EMPTY)) .build()
val playerCommands = MediaSession.ConnectionResult.DEFAULT_PLAYER_COMMANDS.buildUpon() .add(Player.COMMAND_SEEK_TO_NEXT) .add(Player.COMMAND_SEEK_TO_PREVIOUS) .add(Player.COMMAND_SEEK_TO_PREVIOUS_MEDIA_ITEM) // FIX: Important for Triple-Click .add(Player.COMMAND_SEEK_TO_NEXT_MEDIA_ITEM) // FIX: Important for Double-Click .add(Player.COMMAND_PLAY_PAUSE) .build()
return MediaSession.ConnectionResult.AcceptedResultBuilder(session) .setAvailableSessionCommands(sessionCommands) .setAvailablePlayerCommands(playerCommands) .build() }
override fun onCustomCommand( session: MediaSession, controller: MediaSession.ControllerInfo, customCommand: SessionCommand, args: Bundle ): ListenableFuture<SessionResult> { if (customCommand.customAction == CUSTOM_COMMAND_STOP) { session.player.stop() stopForeground(STOP_FOREGROUND_REMOVE) stopSelf() System.exit(0) } return Futures.immediateFuture(SessionResult(SessionResult.RESULT_SUCCESS)) } }
mediaLibrarySession = MediaLibrarySession.Builder(this, player, callback) .setSessionActivity(pendingIntent) .setCustomLayout(ImmutableList.of(prevButton, nextButton, stopButton)) .build()
val defaultProvider = DefaultMediaNotificationProvider.Builder(this).build()
setMediaNotificationProvider(object : MediaNotification.Provider { override fun createNotification( session: MediaSession, customLayout: ImmutableList<CommandButton>, actionFactory: MediaNotification.ActionFactory, onNotificationChangedCallback: MediaNotification.Provider.Callback ): MediaNotification { val mediaNotification = defaultProvider.createNotification( session, ImmutableList.of(prevButton, nextButton, stopButton), actionFactory, onNotificationChangedCallback )
val artworkData = session.player.mediaMetadata.artworkData if (artworkData != null) { val bitmap = BitmapFactory.decodeByteArray(artworkData, 0, artworkData.size) mediaNotification.notification.largeIcon = bitmap }
mediaNotification.notification.color = 0xFF00E5FF.toInt() mediaNotification.notification.extras.putBoolean(android.app.Notification.EXTRA_COLORIZED, true) mediaNotification.notification.extras.putIntArray("android.compactActions", intArrayOf(0, 1, 2))
return mediaNotification }
override fun handleCustomCommand(session: MediaSession, action: String, extras: Bundle): Boolean { return defaultProvider.handleCustomCommand(session, action, extras) } }) }
override fun onGetSession(controllerInfo: MediaSession.ControllerInfo): MediaLibrarySession? = mediaLibrarySession
override fun onDestroy() { mediaLibrarySession?.run { player.release() release() mediaLibrarySession = null } super.onDestroy() } }

package com.example.zion
import android.app.PendingIntent import android.content.Intent import android.graphics.BitmapFactory import android.os.Bundle import androidx.annotation.OptIn import androidx.media3.common.AudioAttributes import androidx.media3.common.C import androidx.media3.common.MediaItem import androidx.media3.common.MediaMetadata import androidx.media3.common.Player import androidx.media3.common.util.UnstableApi import androidx.media3.exoplayer.ExoPlayer import androidx.media3.session.CommandButton import androidx.media3.session.DefaultMediaNotificationProvider import androidx.media3.session.LibraryResult import androidx.media3.session.MediaLibraryService import androidx.media3.session.MediaNotification import androidx.media3.session.MediaSession import androidx.media3.session.SessionCommand import androidx.media3.session.SessionResult import com.google.common.collect.ImmutableList import com.google.common.util.concurrent.Futures import com.google.common.util.concurrent.ListenableFuture
class PlaybackService : MediaLibraryService() { private var mediaLibrarySession: MediaLibrarySession? = null
companion object { const val CUSTOM_COMMAND_STOP = "STOP_APP" }
@OptIn(UnstableApi::class) override fun onCreate() { super.onCreate()
val audioAttributes = AudioAttributes.Builder() .setContentType(C.AUDIO_CONTENT_TYPE_MUSIC) .setUsage(C.USAGE_MEDIA) .build()
val player = ExoPlayer.Builder(this) .setAudioAttributes(audioAttributes, true) .setHandleAudioBecomingNoisy(true) .build()
val intent = Intent(this, MainActivity::class.java) val pendingIntent = PendingIntent.getActivity( this, 0, intent, PendingIntent.FLAG_IMMUTABLE )
// Previous Button val prevButton = CommandButton.Builder() .setPlayerCommand(Player.COMMAND_SEEK_TO_PREVIOUS) .setIconResId(android.R.drawable.ic_media_previous) .setDisplayName("Previous") .build()
// Next Button val nextButton = CommandButton.Builder() .setPlayerCommand(Player.COMMAND_SEEK_TO_NEXT) .setIconResId(android.R.drawable.ic_media_next) .setDisplayName("Next") .build()
// Stop Button val stopButton = CommandButton.Builder() .setSessionCommand(SessionCommand(CUSTOM_COMMAND_STOP, Bundle.EMPTY)) .setIconResId(android.R.drawable.ic_menu_close_clear_cancel) .setDisplayName("Close") .build()
val callback = object : MediaLibrarySession.Callback { override fun onGetLibraryRoot( session: MediaLibrarySession, browser: MediaSession.ControllerInfo, params: LibraryParams? ): ListenableFuture<LibraryResult<MediaItem>> { val rootMetadata = MediaMetadata.Builder() .setIsBrowsable(true) .setIsPlayable(false) .setMediaType(MediaMetadata.MEDIA_TYPE_FOLDER_MIXED) .setTitle("ZION_ROOT") .build()
val rootItem = MediaItem.Builder() .setMediaId("root") .setMediaMetadata(rootMetadata) .build()
return Futures.immediateFuture(LibraryResult.ofItem(rootItem, params)) }
override fun onConnect( session: MediaSession, controller: MediaSession.ControllerInfo ): MediaSession.ConnectionResult { val sessionCommands = MediaSession.ConnectionResult.DEFAULT_SESSION_COMMANDS.buildUpon() .add(SessionCommand(CUSTOM_COMMAND_STOP, Bundle.EMPTY)) .build()
val playerCommands = MediaSession.ConnectionResult.DEFAULT_PLAYER_COMMANDS.buildUpon() .add(Player.COMMAND_SEEK_TO_NEXT) .add(Player.COMMAND_SEEK_TO_PREVIOUS) .add(Player.COMMAND_SEEK_TO_PREVIOUS_MEDIA_ITEM) // FIX: Important for Triple-Click .add(Player.COMMAND_SEEK_TO_NEXT_MEDIA_ITEM) // FIX: Important for Double-Click .add(Player.COMMAND_PLAY_PAUSE) .build()
return MediaSession.ConnectionResult.AcceptedResultBuilder(session) .setAvailableSessionCommands(sessionCommands) .setAvailablePlayerCommands(playerCommands) .build() }
override fun onCustomCommand( session: MediaSession, controller: MediaSession.ControllerInfo, customCommand: SessionCommand, args: Bundle ): ListenableFuture<SessionResult> { if (customCommand.customAction == CUSTOM_COMMAND_STOP) { session.player.stop() stopForeground(STOP_FOREGROUND_REMOVE) stopSelf() System.exit(0) } return Futures.immediateFuture(SessionResult(SessionResult.RESULT_SUCCESS)) } }
mediaLibrarySession = MediaLibrarySession.Builder(this, player, callback) .setSessionActivity(pendingIntent) .setCustomLayout(ImmutableList.of(prevButton, nextButton, stopButton)) .build()
val defaultProvider = DefaultMediaNotificationProvider.Builder(this).build()
setMediaNotificationProvider(object : MediaNotification.Provider { override fun createNotification( session: MediaSession, customLayout: ImmutableList<CommandButton>, actionFactory: MediaNotification.ActionFactory, onNotificationChangedCallback: MediaNotification.Provider.Callback ): MediaNotification { val mediaNotification = defaultProvider.createNotification( session, ImmutableList.of(prevButton, nextButton, stopButton), actionFactory, onNotificationChangedCallback )
val artworkData = session.player.mediaMetadata.artworkData if (artworkData != null && artworkData.isNotEmpty()) { val bitmap = BitmapFactory.decodeByteArray(artworkData, 0, artworkData.size) if (bitmap != null) { mediaNotification.notification.largeIcon = bitmap } }
mediaNotification.notification.color = 0xFF00E5FF.toInt() mediaNotification.notification.extras.putBoolean(android.app.Notification.EXTRA_COLORIZED, true) mediaNotification.notification.extras.putIntArray("android.compactActions", intArrayOf(0, 1, 2))
